SELECT id, tax_no, enterprise_name, region_code, security_account_name, status, remark, gmt_create, gmt_modified
FROM tb_tax_enterprise
WHERE id = #{id}

SELECT id, tax_no, enterprise_name, region_code, security_account_name, status, remark, gmt_create, gmt_modified
FROM tb_tax_enterprise
WHERE tax_no = #{taxNo}

SELECT id, region_code, site_type, etax_entry_url, tpass_base_url, login_success_url,
       login_button_text, gt4_base_url, declaration_query_url, declaration_query_menu_id,
       social_security_payment_flow_json, status, remark, gmt_create, gmt_modified
FROM tb_tax_region_site
WHERE region_code = #{regionCode}
  AND site_type = #{siteType}
